"package com.example.sophiaquest.data

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import androidx.room.Update
import kotlinx.coroutines.flow.Flow

@Dao
interface SophiaQuestDao {

    // --- TASKS ---
    @Query("SELECT * FROM tasks WHERE isArchived = 0 ORDER BY id DESC")
    fun getActiveTasks(): Flow<List<Task>>

    @Query("SELECT * FROM tasks WHERE id = :id LIMIT 1")
    suspend fun getTaskById(id: Long): Task?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertTask(task: Task): Long

    @Update
    suspend fun updateTask(task: Task)

    @Query("UPDATE tasks SET isArchived = 1 WHERE id = :taskId")
    suspend fun archiveTask(taskId: Long)


    // --- TASK COMPLETIONS ---
    @Query("SELECT * FROM task_completions WHERE completionDate = :date")
    fun getCompletionsForDate(date: String): Flow<List<TaskCompletion>>

    @Query("SELECT * FROM task_completions WHERE taskId = :taskId AND completionDate = :date LIMIT 1")
    suspend fun getCompletion(taskId: Long, date: String): TaskCompletion?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertCompletion(completion: TaskCompletion): Long

    @Query("DELETE FROM task_completions WHERE taskId = :taskId AND completionDate = :date")
    suspend fun deleteCompletion(taskId: Long, date: String)

    @Query("DELETE FROM task_completions WHERE id = :completionId")
    suspend fun deleteCompletionById(completionId: Long)


    // --- LEDGER ENTRIES ---
    @Query("SELECT * FROM ledger_entries ORDER BY timestamp ASC")
    fun getAllLedgerEntries(): Flow<List<LedgerEntry>>

    @Query("SELECT SUM(amountCents) FROM ledger_entries WHERE jarType = :jarType")
