"    // Completes a task for the current day.
    // If it's a routine task, it immediately awards stars upon completion.
    // If it's an extra job, it is set to PENDING_APPROVAL and parent must approve it to award cash.
    suspend fun completeTask(taskId: Long, date: String, autoApprove: Boolean = false) {
        mutex.withLock {
            val task = dao.getTaskById(taskId) ?: return@withLock

            val status = if (task.isExtraJob && !autoApprove) "PENDING_APPROVAL" else "APPROVED"
            val completion = TaskCompletion(
                taskId = taskId,
                completionDate = date,
                status = status
            )

            dao.insertCompletion(completion)

            if (status == "APPROVED") {
                awardCompletionRewards(task)
            }
        }
    }

    suspend fun undoCompletion(taskId: Long, date: String) {
        mutex.withLock {
            val completion = dao.getCompletion(taskId, date) ?: return@withLock

            // If it was already approved, we need to deduct the rewards
            if (completion.status == "APPROVED") {
                val task = dao.getTaskById(taskId)
                if (task != null) {
                    deductCompletionRewards(task)
                }
            }

            dao.deleteCompletion(taskId, date)
