"    @Volatile var volumeScale: Float = 1.0f

    fun playMusicNote(freq: Double, durationMs: Int) {
        val numSamples = (SAMPLE_RATE * (durationMs / 1000.0)).toInt()
        val buffer = ShortArray(numSamples)
        for (i in 0 until numSamples) {
            val t = i.toDouble() / SAMPLE_RATE
            val angle = 2.0 * Math.PI * freq * t
            // Retro square/triangle wave
            val raw = if (sin(angle) > 0) 1.0 else -1.0
            val envelope = 1.0 - (i.toDouble() / numSamples) * 0.2
            buffer[i] = (raw * 4000.0 * envelope).toInt().toShort()
        }
        playPcm(buffer)
    }

    private fun playPcm(buffer: ShortArray) {
        val currentScale = volumeScale
        val scaledBuffer = ShortArray(buffer.size)
        for (i in buffer.indices) {
            scaledBuffer[i] = (buffer[i] * currentScale).toInt().coerceIn(-32768, 32767).toShort()
        }

        Thread {
            try {
                val track = AudioTrack(
                    AudioManager.STREAM_MUSIC,
                    SAMPLE_RATE,
                    AudioFormat.CHANNEL_OUT_MONO,
                    AudioFormat.ENCODING_PCM_16BIT,
                    scaledBuffer.size * 2,
                    AudioTrack.MODE_STATIC
                )
                track.write(scaledBuffer, 0, scaledBuffer.size)
                track.play()
                val playDurationMs = (scaledBuffer.size * 1000L) / SAMPLE_RATE
                Thread.sleep(playDurationMs + 50)
                track.stop()
                track.release()
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()
    }"

